SELECT r.id AS "registerId", r.case_number AS "caseNumber", r.real_name AS "realName", r.gender AS "gender", r.age AS "age", r.deptment_id AS "departmentId", COALESCE(fp.priority_level, 'normal') AS "priorityLevel", COALESCE(fp.interview_interval_days, 7) AS "interviewIntervalDays", COALESCE(fp.observation_interval_days, 1) AS "observationIntervalDays", (fp.register_id IS NOT NULL AND fp.department_id = #{departmentId}) AS "enrolled", ( SELECT MAX(s.schedule_date) FROM follow_up_day_schedule s WHERE s.register_id = r.id AND s.item_type = 'interview' AND s.status = 'completed' ) AS "lastInterviewDate", EXISTS ( SELECT 1 FROM follow_up_daily_observation o WHERE o.register_id = r.id AND o.observation_date = #{targetDate} ) AS "observedToday", EXISTS ( SELECT 1 FROM follow_up_day_schedule s WHERE s.register_id = r.id AND s.schedule_date = #{targetDate} AND s.item_type = 'interview' AND s.status = 'planned' ) AS "interviewScheduledToday", ( SELECT MAX(s.schedule_date) FROM follow_up_day_schedule s WHERE s.register_id = r.id AND s.item_type IN ('interview', 'observation') AND s.status IN ('planned', 'completed') ) AS "lastTrackedDate" FROM register r LEFT JOIN follow_up_patient_profile fp ON fp.register_id = r.id WHERE
AND fp.department_id = #{departmentId}
AND ( fp.department_id = #{departmentId}
OR fp.register_id IS NULL
)
ORDER BY CASE COALESCE(fp.priority_level, 'normal') WHEN 'critical' THEN 1 WHEN 'high' THEN 2 ELSE 3 END, r.real_name

SELECT DISTINCT tracked_date AS "trackedDate", tracked_type AS "trackedType"
FROM (
    SELECT s.schedule_date AS tracked_date, s.item_type AS tracked_type
    FROM follow_up_day_schedule s
    WHERE s.register_id = #{registerId}
      AND s.status IN ('planned', 'completed')
      AND s.schedule_date BETWEEN #{from} AND #{to}
    UNION
    SELECT o.observation_date AS tracked_date, 'observation' AS tracked_type
    FROM follow_up_daily_observation o
    WHERE o.register_id = #{registerId}
      AND o.observation_date BETWEEN #{from} AND #{to}
    UNION
    SELECT pho.observed_at::date AS tracked_date, 'metric' AS tracked_type
    FROM patient_health_observation pho
    WHERE pho.register_id = #{registerId}
      AND pho.observed_at::date BETWEEN #{from} AND #{to}
) t
ORDER BY tracked_date DESC

SELECT s.id AS "id", s.register_id AS "registerId", s.department_id AS "departmentId", s.schedule_date AS "scheduleDate", s.item_type AS "itemType", s.title AS "title", s.status AS "status", s.created_by AS "createdBy", s.creation_time AS "creationTime", r.real_name AS "patientName", r.case_number AS "caseNumber" FROM follow_up_day_schedule s LEFT JOIN register r ON r.id = s.register_id
s.department_id = #{departmentId}
AND s.schedule_date >= #{from}
AND s.schedule_date <= #{to}
ORDER BY s.schedule_date ASC, s.id ASC

SELECT id AS "id"
FROM follow_up_day_schedule
WHERE register_id = #{registerId}
  AND schedule_date = #{scheduleDate}
  AND item_type = 'interview'
LIMIT 1

